// ---- src/infra/dates.ts ----
var DateInfra = {
  nowIso: function () {
    return Utilities.formatDate(new Date(), APP_CONFIG.timezone, "yyyy-MM-dd'T'HH:mm:ssXXX");
  },

  isDateString: function (value) {
    return typeof value === "string" && /^\d{4}-\d{2}-\d{2}$/.test(value);
  },

  compareIsoLike: function (left, right) {
    var leftValue = left || "";
    var rightValue = right || "";

    if (leftValue === rightValue) {
      return 0;
    }

    return leftValue > rightValue ? 1 : -1;
  },
};

// ---- src/infra/slug.ts ----
var SlugInfra = {
  slugify: function (value) {
    return String(value || "")
      .trim()
      .toLowerCase()
      .replace(/[^\w\u3040-\u30ff\u3400-\u9fff-]+/g, "-")
      .replace(/-+/g, "-")
      .replace(/^-|-$/g, "");
  },

  buildSessionKey: function (openedOn, name, location) {
    var datePart = openedOn || "";
    var namePart = SlugInfra.slugify(name || "");
    var locationPart = SlugInfra.slugify(location || "");
    var parts = [datePart, namePart, locationPart].filter(function (part) {
      return part !== "";
    });
    var built = parts.join("_");

    return built || IdInfra.generateRecordId();
  },
};

// ---- src/infra/sheets.ts ----
var SheetsInfra = {
  getSpreadsheetId: function () {
    var props = PropertiesService.getScriptProperties();
    var spreadsheetId = props.getProperty(APP_CONFIG.spreadsheetIdProperty);

    if (!spreadsheetId) {
      throw new Error("Missing Script Property: " + APP_CONFIG.spreadsheetIdProperty);
    }

    return spreadsheetId;
  },

  getSpreadsheet: function () {
    return SpreadsheetApp.openById(SheetsInfra.getSpreadsheetId());
  },

  getSheetConfigList: function () {
    return [
      { name: APP_CONFIG.sheetNames.wineLog, columns: APP_CONFIG.wineLogColumns },
      { name: APP_CONFIG.sheetNames.wineSession, columns: APP_CONFIG.wineSessionColumns },
      { name: APP_CONFIG.sheetNames.userProfile, columns: APP_CONFIG.userProfileColumns },
    ];
  },

  ensureAllSheets: function () {
    var spreadsheet = SheetsInfra.getSpreadsheet();
    var configs = SheetsInfra.getSheetConfigList();

    configs.forEach(function (config) {
      SheetsInfra.ensureSheet(spreadsheet, config.name, config.columns);
    });
  },

  ensureSheet: function (spreadsheet, sheetName, columns) {
    var sheet = spreadsheet.getSheetByName(sheetName);

    if (!sheet) {
      sheet = spreadsheet.insertSheet(sheetName);
    }

    var currentColumns = [];

    if (sheet.getLastRow() > 0) {
      currentColumns = sheet.getRange(1, 1, 1, sheet.getLastColumn()).getValues()[0];
    }

    if (currentColumns.join("|") !== columns.join("|")) {
      sheet.clearContents();
      sheet.getRange(1, 1, 1, columns.length).setValues([columns]);
    }

    var headerRange = sheet.getRange(1, 1, 1, columns.length);
    headerRange.setFontWeight("bold");
    headerRange.setBackground("#1f2937");
    headerRange.setFontColor("#ffffff");
    sheet.setFrozenRows(1);

    var widthMap = APP_CONFIG.columnWidths[sheetName] || {};
    Object.keys(widthMap).forEach(function (columnNumber) {
      sheet.setColumnWidth(Number(columnNumber), widthMap[columnNumber]);
    });

    return sheet;
  },

  getSheet: function (sheetName) {
    var spreadsheet = SheetsInfra.getSpreadsheet();
    var configs = SheetsInfra.getSheetConfigList();
    var matched = configs.filter(function (config) {
      return config.name === sheetName;
    })[0];

    if (!matched) {
      throw new Error("Unknown sheet: " + sheetName);
    }

    return SheetsInfra.ensureSheet(spreadsheet, sheetName, matched.columns);
  },

  readObjects: function (sheetName, columns) {
    var sheet = SheetsInfra.getSheet(sheetName);
    var lastRow = sheet.getLastRow();

    if (lastRow < 2) {
      return [];
    }

    var rows = sheet.getRange(2, 1, lastRow - 1, columns.length).getValues();

    return rows.map(function (row, index) {
      return SheetsInfra.rowToObject(columns, row, index + 2);
    });
  },

  rowToObject: function (columns, row, rowNumber) {
    var output = {};

    columns.forEach(function (column, index) {
      output[column] = row[index];
    });

    output.__rowNumber = rowNumber;
    return output;
  },

  appendObject: function (sheetName, columns, object) {
    var sheet = SheetsInfra.getSheet(sheetName);
    var row = SheetsInfra.objectToRow(columns, object);
    sheet.appendRow(row);
    return sheet.getLastRow();
  },

  updateObject: function (sheetName, columns, rowNumber, object) {
    var sheet = SheetsInfra.getSheet(sheetName);
    var row = SheetsInfra.objectToRow(columns, object);
    sheet.getRange(rowNumber, 1, 1, columns.length).setValues([row]);
  },

  objectToRow: function (columns, object) {
    return columns.map(function (column) {
      var value = object[column];
      return value === undefined || value === null ? "" : value;
    });
  },

  findObjectByColumn: function (sheetName, columns, columnName, expectedValue) {
    var rows = SheetsInfra.readObjects(sheetName, columns);

    for (var index = rows.length - 1; index >= 0; index -= 1) {
      if (String(rows[index][columnName]) === String(expectedValue)) {
        return rows[index];
      }
    }

    return null;
  },

  sortByUpdatedAtDesc: function (items) {
    return items.slice().sort(function (left, right) {
      return DateInfra.compareIsoLike(right.updated_at || "", left.updated_at || "");
    });
  },
};

// ---- src/domain/validation.ts ----
var ValidationDomain = {
  assertActionPresent: function (payload) {
    if (!payload || typeof payload.action !== "string" || payload.action.trim() === "") {
      throw ValidationDomain.buildError("action is required", 400);
    }
  },

  validateRecordPayload: function (payload) {
    var errors = [];
    var requiredFields = ["date", "opened_on", "type", "name"];

    requiredFields.forEach(function (fieldName) {
      if (!payload || payload[fieldName] === undefined || payload[fieldName] === null || payload[fieldName] === "") {
        errors.push(fieldName + " is required");
      }
    });

    if (!DateInfra.isDateString(payload.date)) {
      errors.push("date must be YYYY-MM-DD");
    }

    if (!DateInfra.isDateString(payload.opened_on)) {
      errors.push("opened_on must be YYYY-MM-DD");
    }

    if (!Number.isInteger(Number(payload.open_day)) || Number(payload.open_day) < 1) {
      errors.push("open_day must be an integer >= 1");
    }

    if (APP_CONFIG.allowedWineTypes.indexOf(payload.type) === -1) {
      errors.push("type must be one of: " + APP_CONFIG.allowedWineTypes.join(", "));
    }

    ValidationDomain.assertOptionalInteger(payload.vintage, "vintage", errors);
    ValidationDomain.assertOptionalNumber(payload.overall_score_5, "overall_score_5", errors);
    ValidationDomain.assertArray(payload.aroma, "aroma", errors);
    ValidationDomain.assertArray(payload.tags, "tags", errors);
    ValidationDomain.assertArray(payload.meta && payload.meta.inferred_fields, "meta.inferred_fields", errors);
    ValidationDomain.assertArray(payload.grape_varieties, "grape_varieties", errors);
    ValidationDomain.assertRatings(payload.ratings, errors);
    ValidationDomain.assertPairedDishes(payload.paired_dishes, errors);
    ValidationDomain.assertScene(payload.scene, errors);

    if (errors.length > 0) {
      throw ValidationDomain.buildError(errors.join("; "), 400);
    }
  },

  assertOptionalInteger: function (value, label, errors) {
    if (value === null || value === undefined || value === "") {
      return;
    }

    if (!Number.isInteger(Number(value))) {
      errors.push(label + " must be an integer or null");
    }
  },

  assertOptionalNumber: function (value, label, errors) {
    if (value === null || value === undefined || value === "") {
      return;
    }

    if (!Number.isFinite(Number(value))) {
      errors.push(label + " must be a number or null");
    }
  },

  assertArray: function (value, label, errors) {
    if (value === null || value === undefined) {
      return;
    }

    if (!Array.isArray(value)) {
      errors.push(label + " must be an array");
    }
  },

  assertRatings: function (ratings, errors) {
    if (ratings === null || ratings === undefined) {
      return;
    }

    if (typeof ratings !== "object" || Array.isArray(ratings)) {
      errors.push("ratings must be an object");
      return;
    }

    ["color", "aroma", "tannin", "acidity", "fruit"].forEach(function (key) {
      ValidationDomain.assertOptionalNumber(ratings[key], "ratings." + key, errors);
    });
  },

  assertPairedDishes: function (pairedDishes, errors) {
    if (pairedDishes === null || pairedDishes === undefined) {
      return;
    }

    if (typeof pairedDishes !== "object" || Array.isArray(pairedDishes)) {
      errors.push("paired_dishes must be an object");
      return;
    }

    ["main", "appetizer", "side", "dessert", "drink_other"].forEach(function (key) {
      ValidationDomain.assertArray(pairedDishes[key], "paired_dishes." + key, errors);
    });
  },

  assertScene: function (scene, errors) {
    if (scene === null || scene === undefined) {
      return;
    }

    if (typeof scene !== "object" || Array.isArray(scene)) {
      errors.push("scene must be an object");
    }
  },

  buildError: function (message, code) {
    var error = new Error(message);
    error.code = code;
    return error;
  },
};

// ---- src/domain/wineLog.ts ----
var WineLogDomain = {
  getAllRows: function () {
    var rows = SheetsInfra.readObjects(APP_CONFIG.sheetNames.wineLog, APP_CONFIG.wineLogColumns);
    return rows.map(WineLogDomain.parseRow);
  },

  getActiveRows: function () {
    return WineLogDomain.getAllRows().filter(function (row) {
      return row.deleted_flag !== true;
    });
  },

  findByRecordId: function (recordId) {
    if (!recordId) {
      return null;
    }

    var found = SheetsInfra.findObjectByColumn(
      APP_CONFIG.sheetNames.wineLog,
      APP_CONFIG.wineLogColumns,
      "record_id",
      recordId
    );

    return found ? WineLogDomain.parseRow(found) : null;
  },

  upsertRecord: function (payload) {
    ValidationDomain.validateRecordPayload(payload);

    var existing = payload.record_id ? WineLogDomain.findByRecordId(payload.record_id) : null;
    var normalized = WineLogDomain.normalizeRecord(payload, existing);
    var rowObject = WineLogDomain.buildRow(normalized);
    var actionMode = existing ? "update" : "insert";

    if (existing) {
      SheetsInfra.updateObject(
        APP_CONFIG.sheetNames.wineLog,
        APP_CONFIG.wineLogColumns,
        existing.__rowNumber,
        rowObject
      );
    } else {
      var rowNumber = SheetsInfra.appendObject(
        APP_CONFIG.sheetNames.wineLog,
        APP_CONFIG.wineLogColumns,
        rowObject
      );
      normalized.__rowNumber = rowNumber;
    }

    Logger.log(
      "[WineLog] %s record_id=%s session_key=%s",
      actionMode,
      normalized.record_id,
      normalized.session_key
    );
    console.log(
      JSON.stringify({
        area: "WineLog",
        action: actionMode,
        record_id: normalized.record_id,
        session_key: normalized.session_key,
      })
    );

    return {
      mode: actionMode,
      record: normalized,
    };
  },

  normalizeRecord: function (payload, existing) {
    var rawRecord = JsonInfra.sanitizeRawPayload(payload);
    var now = DateInfra.nowIso();
    var recordId = payload.record_id || (existing && existing.record_id) || IdInfra.generateRecordId();
    var openedOn = payload.opened_on || payload.date;
    var sessionKey =
      payload.session_key ||
      (existing && existing.session_key) ||
      SlugInfra.buildSessionKey(openedOn, payload.name, payload.location);
    var pairedDishes = payload.paired_dishes || {};
    var ratings = payload.ratings || {};
    var scene = payload.scene || {};
    var meta = payload.meta || {};

    return {
      record_id: recordId,
      session_key: sessionKey,
      date: payload.date,
      opened_on: openedOn,
      open_day: Number(payload.open_day),
      type: payload.type,
      name: payload.name,
      vintage: WineLogDomain.toIntegerOrNull(payload.vintage),
      producer: payload.producer || "",
      country: payload.country || "",
      region: payload.region || "",
      sub_region: payload.sub_region || "",
      location: payload.location || "",
      grape_varieties: Array.isArray(payload.grape_varieties) ? payload.grape_varieties : [],
      aroma: Array.isArray(payload.aroma) ? payload.aroma : [],
      paired_dishes: {
        main: WineLogDomain.cloneArray(pairedDishes.main),
        appetizer: WineLogDomain.cloneArray(pairedDishes.appetizer),
        side: WineLogDomain.cloneArray(pairedDishes.side),
        dessert: WineLogDomain.cloneArray(pairedDishes.dessert),
        drink_other: WineLogDomain.cloneArray(pairedDishes.drink_other),
      },
      ratings: {
        color: WineLogDomain.toNumberOrNull(ratings.color),
        aroma: WineLogDomain.toNumberOrNull(ratings.aroma),
        tannin: WineLogDomain.toNumberOrNull(ratings.tannin),
        acidity: WineLogDomain.toNumberOrNull(ratings.acidity),
        fruit: WineLogDomain.toNumberOrNull(ratings.fruit),
      },
      overall_score_5: WineLogDomain.toNumberOrNull(payload.overall_score_5),
      overall_grade: payload.overall_grade || WineLogDomain.scoreToGrade(payload.overall_score_5),
      scene: {
        people: scene.people || "",
        style: scene.style || "",
        mood: scene.mood || "",
      },
      repurchase_intent: payload.repurchase_intent || "未定",
      tags: Array.isArray(payload.tags) ? payload.tags : [],
      overall_comment: payload.overall_comment || "",
      meta: {
        inferred_fields: Array.isArray(meta.inferred_fields) ? meta.inferred_fields : [],
        notes: meta.notes || "",
      },
      summary_jp: payload.summary_jp || "",
      raw_json: JsonInfra.stringify(rawRecord),
      created_at: existing ? existing.created_at : now,
      updated_at: now,
      deleted_flag: false,
      __rowNumber: existing ? existing.__rowNumber : null,
    };
  },

  buildRow: function (record) {
    return {
      record_id: record.record_id,
      session_key: record.session_key,
      date: record.date,
      opened_on: record.opened_on,
      open_day: record.open_day,
      type: record.type,
      name: record.name,
      vintage: record.vintage,
      producer: record.producer,
      country: record.country,
      region: record.region,
      sub_region: record.sub_region,
      location: record.location,
      grape_varieties_json: JsonInfra.stringify(record.grape_varieties),
      aroma_json: JsonInfra.stringify(record.aroma),
      paired_dishes_json: JsonInfra.stringify(record.paired_dishes),
      ratings_color: record.ratings.color,
      ratings_aroma: record.ratings.aroma,
      ratings_tannin: record.ratings.tannin,
      ratings_acidity: record.ratings.acidity,
      ratings_fruit: record.ratings.fruit,
      overall_score_5: record.overall_score_5,
      overall_grade: record.overall_grade,
      scene_people: record.scene.people,
      scene_style: record.scene.style,
      scene_mood: record.scene.mood,
      repurchase_intent: record.repurchase_intent,
      tags_json: JsonInfra.stringify(record.tags),
      overall_comment: record.overall_comment,
      meta_inferred_fields_json: JsonInfra.stringify(record.meta.inferred_fields),
      meta_notes: record.meta.notes,
      summary_jp: record.summary_jp,
      raw_json: record.raw_json,
      created_at: record.created_at,
      updated_at: record.updated_at,
      deleted_flag: record.deleted_flag,
    };
  },

  parseRow: function (row) {
    return {
      record_id: row.record_id,
      session_key: row.session_key,
      date: row.date,
      opened_on: row.opened_on,
      open_day: WineLogDomain.toIntegerOrNull(row.open_day),
      type: row.type,
      name: row.name,
      vintage: WineLogDomain.toIntegerOrNull(row.vintage),
      producer: row.producer,
      country: row.country,
      region: row.region,
      sub_region: row.sub_region,
      location: row.location,
      grape_varieties: JsonInfra.parse(row.grape_varieties_json, []),
      aroma: JsonInfra.parse(row.aroma_json, []),
      paired_dishes: JsonInfra.parse(row.paired_dishes_json, {
        main: [],
        appetizer: [],
        side: [],
        dessert: [],
        drink_other: [],
      }),
      ratings: {
        color: WineLogDomain.toNumberOrNull(row.ratings_color),
        aroma: WineLogDomain.toNumberOrNull(row.ratings_aroma),
        tannin: WineLogDomain.toNumberOrNull(row.ratings_tannin),
        acidity: WineLogDomain.toNumberOrNull(row.ratings_acidity),
        fruit: WineLogDomain.toNumberOrNull(row.ratings_fruit),
      },
      overall_score_5: WineLogDomain.toNumberOrNull(row.overall_score_5),
      overall_grade: row.overall_grade || "",
      scene: {
        people: row.scene_people || "",
        style: row.scene_style || "",
        mood: row.scene_mood || "",
      },
      repurchase_intent: row.repurchase_intent || "",
      tags: JsonInfra.parse(row.tags_json, []),
      overall_comment: row.overall_comment || "",
      meta: {
        inferred_fields: JsonInfra.parse(row.meta_inferred_fields_json, []),
        notes: row.meta_notes || "",
      },
      summary_jp: row.summary_jp || "",
      raw_json: row.raw_json || "",
      created_at: row.created_at || "",
      updated_at: row.updated_at || "",
      deleted_flag: WineLogDomain.toBoolean(row.deleted_flag),
      __rowNumber: row.__rowNumber,
    };
  },

  listRecentRecords: function (limit) {
    var parsed = WineLogDomain.getActiveRows();
    var sorted = parsed.sort(function (left, right) {
      return DateInfra.compareIsoLike(right.updated_at, left.updated_at);
    });

    return sorted.slice(0, limit);
  },

  cloneArray: function (value) {
    return Array.isArray(value) ? value.slice() : [];
  },

  toIntegerOrNull: function (value) {
    if (value === null || value === undefined || value === "") {
      return null;
    }

    var numeric = Number(value);
    return Number.isInteger(numeric) ? numeric : null;
  },

  toNumberOrNull: function (value) {
    if (value === null || value === undefined || value === "") {
      return null;
    }

    var numeric = Number(value);
    return Number.isFinite(numeric) ? numeric : null;
  },

  toBoolean: function (value) {
    return value === true || value === "TRUE" || value === "true";
  },

  scoreToGrade: function (score) {
    var numericScore = WineLogDomain.toNumberOrNull(score);

    if (numericScore === null) {
      return "";
    }

    if (numericScore >= 4.5) {
      return "A";
    }

    if (numericScore >= 3.5) {
      return "B";
    }

    return "C";
  },

  toApiRecord: function (record) {
    return {
      record_id: record.record_id,
      session_key: record.session_key,
      date: record.date,
      opened_on: record.opened_on,
      open_day: record.open_day,
      type: record.type,
      name: record.name,
      vintage: record.vintage,
      producer: record.producer,
      country: record.country,
      region: record.region,
      sub_region: record.sub_region,
      location: record.location,
      grape_varieties: record.grape_varieties,
      aroma: record.aroma,
      paired_dishes: record.paired_dishes,
      ratings: record.ratings,
      overall_score_5: record.overall_score_5,
      overall_grade: record.overall_grade,
      scene: record.scene,
      repurchase_intent: record.repurchase_intent,
      tags: record.tags,
      overall_comment: record.overall_comment,
      meta: record.meta,
      summary_jp: record.summary_jp,
      raw_json: record.raw_json,
      created_at: record.created_at,
      updated_at: record.updated_at,
      deleted_flag: record.deleted_flag,
    };
  },
};

