// ---- src/api/handlers.ts ----
var ApiHandlers = {
  health: function () {
    var spreadsheetId = "";
    var sheetStatus = {};

    try {
      spreadsheetId = SheetsInfra.getSpreadsheetId();
      sheetStatus = {
        WineLog: !!SheetsInfra.getSheet(APP_CONFIG.sheetNames.wineLog),
        WineSession: !!SheetsInfra.getSheet(APP_CONFIG.sheetNames.wineSession),
        UserProfile: !!SheetsInfra.getSheet(APP_CONFIG.sheetNames.userProfile),
      };
    } catch (error) {
      sheetStatus = {
        configured: false,
        message: String(error.message || error),
      };
    }

    return {
      status: "ok",
      action: "health",
      version: APP_CONFIG.version,
      spreadsheet_id: spreadsheetId,
      sheet_status: sheetStatus,
    };
  },

  upsertRecord: function (payload) {
    SheetsInfra.ensureAllSheets();

    var recordPayload = ApiHandlers.unwrapRecordPayload(payload);
    var result = WineLogDomain.upsertRecord(recordPayload);
    var sessionResult = WineSessionDomain.rebuildSession(result.record.session_key);
    var profileResult = payload.rebuild_profile === true ? UserProfileDomain.rebuildProfile() : null;

    return {
      status: "ok",
      action: "upsertRecord",
      mode: result.mode,
      record: WineLogDomain.toApiRecord(result.record),
      session: sessionResult.session,
      profile: profileResult,
    };
  },

  getRecord: function (payload) {
    var recordId = payload.record_id || payload.id;

    if (!recordId) {
      throw ValidationDomain.buildError("record_id is required", 400);
    }

    var record = WineLogDomain.findByRecordId(recordId);

    if (!record) {
      throw ValidationDomain.buildError("record not found: " + recordId, 404);
    }

    return {
      status: "ok",
      action: "getRecord",
      record: WineLogDomain.toApiRecord(record),
    };
  },

  getSession: function (payload) {
    var sessionKey = payload.session_key;

    if (!sessionKey) {
      throw ValidationDomain.buildError("session_key is required", 400);
    }

    var result = WineSessionDomain.getSession(sessionKey);

    if (!result) {
      throw ValidationDomain.buildError("session not found: " + sessionKey, 404);
    }

    return {
      status: "ok",
      action: "getSession",
      session: result.session,
      records: result.records.map(WineLogDomain.toApiRecord),
    };
  },

  findSession: function (payload) {
    var sessions = WineSessionDomain.findSession(payload);

    return {
      status: "ok",
      action: "findSession",
      count: sessions.length,
      sessions: sessions,
    };
  },

  listRecentRecords: function (payload) {
    var limit = Number(payload.limit || payload.n || 20);
    var safeLimit = Number.isFinite(limit) ? Math.min(Math.max(limit, 1), 100) : 20;
    var records = WineLogDomain.listRecentRecords(safeLimit).map(WineLogDomain.toApiRecord);

    return {
      status: "ok",
      action: "listRecentRecords",
      count: records.length,
      records: records,
    };
  },

  rebuildSession: function (payload) {
    var result = WineSessionDomain.rebuildSession(payload.session_key);

    return {
      status: "ok",
      action: "rebuildSession",
      session: result.session,
      records: result.records.map(WineLogDomain.toApiRecord),
    };
  },

  rebuildUserProfile: function () {
    SheetsInfra.ensureAllSheets();
    var profile = UserProfileDomain.rebuildProfile();

    return {
      status: "ok",
      action: "rebuildUserProfile",
      profile: profile,
    };
  },

  unwrapRecordPayload: function (payload) {
    if (payload.record && typeof payload.record === "object" && !Array.isArray(payload.record)) {
      return JsonInfra.sanitizeRawPayload(payload.record);
    }

    var cloned = JsonInfra.sanitizeRawPayload(payload);

    delete cloned.action;
    delete cloned.rebuild_profile;
    delete cloned.api_key;

    return cloned;
  },
};

// ---- src/api/router.ts ----
var ApiRouter = {
  handleRequest: function (method, payload, query) {
    var mergedPayload = ApiRouter.mergePayload(payload, query);
    var action = String(mergedPayload.action || "").trim();

    if (!action) {
      throw ValidationDomain.buildError("action is required", 400);
    }

    ApiRouter.authorize(mergedPayload, query);
    ApiRouter.logRequest(method, action, mergedPayload);

    switch (action) {
      case "health":
        return ApiHandlers.health(mergedPayload);
      case "upsertRecord":
        return ApiHandlers.upsertRecord(mergedPayload);
      case "getRecord":
        return ApiHandlers.getRecord(mergedPayload);
      case "getSession":
        return ApiHandlers.getSession(mergedPayload);
      case "findSession":
        return ApiHandlers.findSession(mergedPayload);
      case "listRecentRecords":
        return ApiHandlers.listRecentRecords(mergedPayload);
      case "rebuildSession":
        return ApiHandlers.rebuildSession(mergedPayload);
      case "rebuildUserProfile":
        return ApiHandlers.rebuildUserProfile(mergedPayload);
      default:
        throw ValidationDomain.buildError("Unknown action: " + action, 400);
    }
  },

  mergePayload: function (payload, query) {
    var output = {};
    var sourcePayload = payload || {};
    var sourceQuery = query || {};

    Object.keys(sourceQuery).forEach(function (key) {
      output[key] = sourceQuery[key];
    });

    Object.keys(sourcePayload).forEach(function (key) {
      output[key] = sourcePayload[key];
    });

    return output;
  },

  authorize: function (payload, query) {
    var scriptApiKey = PropertiesService.getScriptProperties().getProperty(APP_CONFIG.apiKeyProperty);

    if (!scriptApiKey) {
      return;
    }

    var bodyKey = payload && payload._api_key ? payload._api_key : "";
    var queryKey = query && query.api_key ? query.api_key : "";

    if (bodyKey === scriptApiKey || queryKey === scriptApiKey) {
      return;
    }

    throw ValidationDomain.buildError("Invalid API key", 401);
  },

  parsePostPayload: function (e) {
    if (!e || !e.postData || !e.postData.contents) {
      return {};
    }

    return JSON.parse(e.postData.contents);
  },

  jsonResponse: function (body) {
    return ContentService.createTextOutput(JsonInfra.stringify(body)).setMimeType(
      ContentService.MimeType.JSON
    );
  },

  errorResponse: function (error) {
    var code = error && error.code ? error.code : 500;
    var body = {
      status: "error",
      code: code,
      message: String(error && error.message ? error.message : error),
    };

    console.log(JSON.stringify({ area: "ApiRouter", error: body }));
    Logger.log("[ApiRouter] error code=%s message=%s", code, body.message);
    return ApiRouter.jsonResponse(body);
  },

  logRequest: function (method, action, payload) {
    console.log(
      JSON.stringify({
        area: "ApiRouter",
        method: method,
        action: action,
        record_id: payload.record_id || "",
        session_key: payload.session_key || "",
      })
    );
  },
};

// ---- src/Code.ts ----
function doPost(e) {
  try {
    var payload = ApiRouter.parsePostPayload(e);
    var query = (e && e.parameter) || {};
    var result = ApiRouter.handleRequest("POST", payload, query);
    return ApiRouter.jsonResponse(result);
  } catch (error) {
    return ApiRouter.errorResponse(error);
  }
}

function doGet(e) {
  try {
    var query = (e && e.parameter) || {};
    var result = ApiRouter.handleRequest("GET", {}, query);
    return ApiRouter.jsonResponse(result);
  } catch (error) {
    return ApiRouter.errorResponse(error);
  }
}

function setupSheets() {
  SheetsInfra.ensureAllSheets();
  Logger.log("setupSheets completed");
  return {
    status: "ok",
    message: "Sheets initialized",
    spreadsheet_id: SheetsInfra.getSpreadsheetId(),
  };
}

function insertTestRecord() {
  SheetsInfra.ensureAllSheets();
  return ApiHandlers.upsertRecord(TestFixtures.sampleRecord());
}

function runSmokeTests() {
  SheetsInfra.ensureAllSheets();
  var first = ApiHandlers.upsertRecord(TestFixtures.sampleRecord());
  var secondPayload = TestFixtures.sampleRecord();
  secondPayload.record_id = first.record.record_id;
  secondPayload.open_day = 2;
  secondPayload.summary_jp = "二日目は香りがより開いた。";
  secondPayload.overall_score_5 = 4.9;
  var second = ApiHandlers.upsertRecord(secondPayload);
  var session = ApiHandlers.getSession({ action: "getSession", session_key: second.record.session_key });
  var profile = ApiHandlers.rebuildUserProfile();

  return {
    first: first,
    second: second,
    session: session,
    profile: profile,
  };
}

function onOpen() {
  try {
    SpreadsheetApp.getUi()
      .createMenu("Wine Companion")
      .addItem("Setup Sheets", "setupSheets")
      .addItem("Insert Test Record", "insertTestRecord")
      .addItem("Run Smoke Tests", "runSmokeTests")
      .addToUi();
  } catch (error) {
    Logger.log("onOpen skipped: %s", error.message || error);
  }
}
